244	    private static let sensitiveKeyPatterns = ["token", "key", "secret", "password", "email", "credential"]
245	
246	    static func maskedPayload(_ data: Data) -> String {
247	        guard let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {
248	            return "<non-JSON, \(data.count) bytes>"
249	        }
250	        let masked = maskSensitiveFields(json)
251	        guard let out = try? JSONSerialization.data(withJSONObject: masked, options: [.sortedKeys]),
252	              let str = String(data: out, encoding: .utf8) else {
253	            return "<serialization failed>"
254	        }
255	        return str
256	    }
257	
258	    static func maskSensitiveFields(_ dict: [String: Any]) -> [String: Any] {
259	        var result: [String: Any] = [:]
260	        for (key, value) in dict {
261	            let lower = key.lowercased()
262	            if sensitiveKeyPatterns.contains(where: { lower.contains($0) }) {
263	                result[key] = "***"
264	            } else if let nested = value as? [String: Any] {
265	                result[key] = maskSensitiveFields(nested)
266	            } else if let array = value as? [[String: Any]] {
267	                result[key] = array.map { maskSensitiveFields($0) }
268	            } else {
269	                result[key] = value
270	            }
271	        }
272	        return result
273	    }
274	
275	    // MARK: - Helpers
276	
277	    private func resolvePersistedAccount(
278	        responseEmail: AccountEmail? = nil,
279	        credentials: CodexCredentials? = nil
280	    ) -> (AccountEmail, IdentitySource)? {
281	        if let responseEmail {
282	            _cachedEmail.withLock { $0 = responseEmail }
283	            return (responseEmail, .responseBody)
284	        }
285	        if let accountEmail = credentials?.accountEmail {
286	            _cachedEmail.withLock { $0 = accountEmail }
287	            return (accountEmail, .credentials)
288	        }
289	        if let cached = _cachedEmail.withLock({ $0 }) {
290	            return (cached, .cache)
291	        }
292	        return nil
293	    }
294	
295	    private func errorEntries(
296	        type: String,
297	        credentials: CodexCredentials? = nil,
298	        isActive: Bool = false,
299	        preservedMetrics: [UsageMetric] = []
300	    ) -> [VendorUsageEntry] {
301	        guard let (account, source) = resolvePersistedAccount(credentials: credentials) else {
302	            let accountId = credentials?.accountId.rawValue ?? "<unavailable>"
303	            logger.log(.warning, "Codex identity_unresolved during \(type) for accountId=\(accountId) — no usage entry written")
304	            return []
305	        }
306	        logger.log(.debug, "Codex resolved account=\(account) via \(source.rawValue) for \(type)")
307	        return [errorEntry(account: account, type: type, isActive: isActive, preservedMetrics: preservedMetrics)]
308	    }
309	
310	    private func normalizedEmail(_ rawValue: String?) -> AccountEmail? {
311	        guard let rawValue else { return nil }
312	        let trimmed = rawValue.trimmingCharacters(in: .whitespacesAndNewlines)
313	        guard !trimmed.isEmpty else { return nil }
314	        return AccountEmail(rawValue: trimmed)
315	    }
316	
317	    private func errorEntry(account: AccountEmail, type: String, isActive: Bool = false, preservedMetrics: [UsageMetric] = []) -> VendorUsageEntry {
318	        VendorUsageEntry(
319	            vendor: vendor,
320	            account: account,
321	            isActive: isActive,
322	            lastAcquiredOn: nil,
323	            lastError: UsageError(timestamp: ISODate(date: Date()), type: type),
324	            metrics: preservedMetrics
325	        )
326	    }
327	}
328	
329	public enum CodexConnectorError: Error, CustomStringConvertible {
330	    case unexpectedAPIFormat(receivedKeys: [String])
331	
332	    public var description: String {
333	        switch self {
334	        case let .unexpectedAPIFormat(keys):
335	            "Codex API response does not match expected format — top-level keys: \(keys)"
336	        }
337	    }
338	}
